(window.webpackJsonp=window.webpackJsonp||[]).push([[594],{863:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> OrderedStream = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n</span>) </span>{\\n    <span class=\\"hljs-keyword\\">this</span>.stream=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-literal\\">null</span>)\\n    <span class=\\"hljs-keyword\\">this</span>.startIdx=<span class=\\"hljs-number\\">0</span>\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} id \\n * @param {string} value\\n * @return {string[]}\\n */</span>\\nOrderedStream.prototype.insert = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">id, value</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> idx=id<span class=\\"hljs-number\\">-1</span>\\n    <span class=\\"hljs-keyword\\">this</span>.stream[idx]=value\\n    <span class=\\"hljs-keyword\\">let</span> res=[]\\n    <span class=\\"hljs-keyword\\">while</span>(<span class=\\"hljs-keyword\\">this</span>.stream[<span class=\\"hljs-keyword\\">this</span>.startIdx]!=<span class=\\"hljs-literal\\">null</span>){\\n        res.push(<span class=\\"hljs-keyword\\">this</span>.stream[<span class=\\"hljs-keyword\\">this</span>.startIdx])\\n        <span class=\\"hljs-keyword\\">this</span>.startIdx++\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Your OrderedStream object will be instantiated and called as such:\\n * var obj = new OrderedStream(n)\\n * var param_1 = obj.insert(id,value)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"design-an-ordered-stream","hasThinking":false,"content":"<p>\u6709 <code>n</code> \u4e2a <code>(id, value)</code> \u5bf9\uff0c\u5176\u4e2d <code>id</code> \u662f <code>1</code> \u5230 <code>n</code> \u4e4b\u95f4\u7684\u4e00\u4e2a\u6574\u6570\uff0c<code>value</code> \u662f\u4e00\u4e2a\u5b57\u7b26\u4e32\u3002\u4e0d\u5b58\u5728 <code>id</code> \u76f8\u540c\u7684\u4e24\u4e2a\xa0<code>(id, value)</code> \u5bf9\u3002</p>\\n\\n<p>\u8bbe\u8ba1\u4e00\u4e2a\u6d41\uff0c\u4ee5 <strong>\u4efb\u610f</strong> \u987a\u5e8f\u83b7\u53d6 <code>n</code>\xa0\u4e2a\xa0<code>(id, value)</code>\xa0\u5bf9\uff0c\u5e76\u5728\u591a\u6b21\u8c03\u7528\u65f6 <strong>\u6309 <code>id</code> \u9012\u589e\u7684\u987a\u5e8f</strong> \u8fd4\u56de\u4e00\u4e9b\u503c\u3002</p>\\n\\n<p>\u5b9e\u73b0 <code>OrderedStream</code> \u7c7b\uff1a</p>\\n\\n<ul>\\n\\t<li><code>OrderedStream(int n)</code> \u6784\u9020\u4e00\u4e2a\u80fd\u63a5\u6536 <code>n</code> \u4e2a\u503c\u7684\u6d41\uff0c\u5e76\u5c06\u5f53\u524d\u6307\u9488 <code>ptr</code> \u8bbe\u4e3a <code>1</code> \u3002</li>\\n\\t<li><code>String[] insert(int id, String value)</code> \u5411\u6d41\u4e2d\u5b58\u50a8\u65b0\u7684 <code>(id, value)</code> \u5bf9\u3002\u5b58\u50a8\u540e\uff1a\\n\\t<ul>\\n\\t\\t<li>\u5982\u679c\u6d41\u5b58\u50a8\u6709 <code>id = ptr</code> \u7684 <code>(id, value)</code> \u5bf9\uff0c\u5219\u627e\u51fa\u4ece <code>id = ptr</code> \u5f00\u59cb\u7684 <strong>\u6700\u957f id \u8fde\u7eed\u9012\u589e\u5e8f\u5217</strong> \uff0c\u5e76 <strong>\u6309\u987a\u5e8f</strong> \u8fd4\u56de\u4e0e\u8fd9\u4e9b id \u5173\u8054\u7684\u503c\u7684\u5217\u8868\u3002\u7136\u540e\uff0c\u5c06 <code>ptr</code> \u66f4\u65b0\u4e3a\u6700\u540e\u90a3\u4e2a\xa0 <code>id + 1</code>\xa0\u3002</li>\\n\\t\\t<li>\\n\\t\\t<p>\u5426\u5219\uff0c\u8fd4\u56de\u4e00\u4e2a\u7a7a\u5217\u8868\u3002</p>\\n\\t\\t</li>\\n\\t</ul>\\n\\t</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/11/15/q1.gif\\" style=\\"width: 682px; height: 240px;\\" /></strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165</strong>\\n[\\"OrderedStream\\", \\"insert\\", \\"insert\\", \\"insert\\", \\"insert\\", \\"insert\\"]\\n[[5], [3, \\"ccccc\\"], [1, \\"aaaaa\\"], [2, \\"bbbbb\\"], [5, \\"eeeee\\"], [4, \\"ddddd\\"]]\\n<strong>\u8f93\u51fa</strong>\\n[null, [], [\\"aaaaa\\"], [\\"bbbbb\\", \\"ccccc\\"], [], [\\"ddddd\\", \\"eeeee\\"]]\\n\\n<strong>\u89e3\u91ca</strong>\\nOrderedStream os= new OrderedStream(5);\\nos.insert(3, \\"ccccc\\"); // \u63d2\u5165 (3, \\"ccccc\\")\uff0c\u8fd4\u56de []\\nos.insert(1, \\"aaaaa\\"); // \u63d2\u5165 (1, \\"aaaaa\\")\uff0c\u8fd4\u56de [\\"aaaaa\\"]\\nos.insert(2, \\"bbbbb\\"); // \u63d2\u5165 (2, \\"bbbbb\\")\uff0c\u8fd4\u56de [\\"bbbbb\\", \\"ccccc\\"]\\nos.insert(5, \\"eeeee\\"); // \u63d2\u5165 (5, \\"eeeee\\")\uff0c\u8fd4\u56de []\\nos.insert(4, \\"ddddd\\"); // \u63d2\u5165 (4, \\"ddddd\\")\uff0c\u8fd4\u56de [\\"ddddd\\", \\"eeeee\\"]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= n <= 1000</code></li>\\n\\t<li><code>1 <= id <= n</code></li>\\n\\t<li><code>value.length == 5</code></li>\\n\\t<li><code>value</code> \u4ec5\u7531\u5c0f\u5199\u5b57\u6bcd\u7ec4\u6210</li>\\n\\t<li>\u6bcf\u6b21\u8c03\u7528 <code>insert</code> \u90fd\u4f1a\u4f7f\u7528\u4e00\u4e2a\u552f\u4e00\u7684 <code>id</code></li>\\n\\t<li>\u6070\u597d\u8c03\u7528 <code>n</code> \u6b21 <code>insert</code></li>\\n</ul>\\n","title":"1656. \u8bbe\u8ba1\u6709\u5e8f\u6d41","relatedTags":["\u8bbe\u8ba1","\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1656"}')}}]);